```python
import threading, time

import itchat

MSG_LIST = []

@itchat.msg_register(TEXT)
def _(msg):
    MSG_LIST.append(msg)

def send_thread():
    while 1:
        if MSG_LIST:
            msg = MSG_LIST.pop()
            itchat.send(msg.text, 'filehelper')
        else:
            time.sleep(.1)

t = threading.Thread(target=send_thread)
