All lollipop types have fields `name` and `description` and you can access them with introspection. Here is example of how lollipop_jsonschema processes them:

```python
import lollipop.types as lt
from lollipop_jsonschema import json_schema
import json


USER = lt.Object({
    'name': lt.String(description='User full name'),
    'age': lt.Integer(description='User age'),
}, name='User', description='User personal data')


ARTICLE = lt.Object({
    'author': lt.Object(USER, description='Article author information'),
})


print json.dumps(json_schema(USER), indent=2)
# {
#   "title": "User", 
#   "description": "User personal data", 
#   "type": "object", 
#   "properties": {
#     "age": {
#       "description": "User age", 
#       "type": "integer"
#     }, 
#     "name": {
#       "description": "User full name", 
#       "type": "string"
#     }
#   }, 
#   "required": [
#     "age", 
#     "name"
#   ]
# }

print json.dumps(json_schema(ARTICLE), indent=2)
# {
#   "type": "object", 
#   "properties": {
#     "author": {
#       "description": "Article author information", 
#       "type": "object", 
#       "properties": {
#         "age": {
#           "description": "User age", 
#           "type": "integer"
#         }, 
#         "name": {
#           "description": "User full name", 
#           "type": "string"
#         }
#       }, 
#       "required": [
#         "age", 
#         "name"
#       ]
#     }
#   }, 
#   "required": [
#     "author"
#   ]
# }
```

